import json

# Get all NASDAQ Capital Market tickers
tickers_list = locals()['var_functions.query_db_102']
print(f"Total tickers to analyze: {len(tickers_list)}")

# Get company descriptions to map tickers to company names
company_desc_query = query_db('stockinfo_database', 'SELECT Symbol, "Company Description" FROM stockinfo WHERE "Market Category" = \'S\'')

# Process company descriptions
company_names = {}
if isinstance(company_desc_query, list):
    for item in company_desc_query:
        symbol = item['Symbol']
        desc = item['Company Description']
        name = desc.split(' specializes')[0].split(' is ')[0].split(' Inc.')[0] + ' Inc.'
        company_names[symbol] = name.strip()
else:
    print("Failed to get company descriptions")
    company_names = {item['Symbol']: item['Symbol'] for item in tickers_list}

print(f"Mapped {len(company_names)} company names")

# Process a subset first to test
results = []
count = 0

for ticker_info in tickers_list:
    ticker = ticker_info['Symbol']
    count += 1

    try:
        # Query 2019 data for this ticker
        query = f"SELECT Date, High, Low FROM {ticker} WHERE Date LIKE '2019-%'"
        stock_data = query_db('stocktrade_database', query)

        # Skip if no data
        if not stock_data or isinstance(stock_data, dict):
            continue

        # Count high volatility days
        high_vol_days = 0
        for day in stock_data:
            try:
                high = float(day['High'])
                low = float(day['Low'])
                if low > 0:
                    intraday_range = high - low
                    pct_of_low = intraday_range / low
                    if pct_of_low > 0.20:
                        high_vol_days += 1
            except:
                continue

        if high_vol_days > 0:
            results.append({
                'ticker': ticker,
                'company_name': company_names.get(ticker, ticker),
                'high_vol_days': high_vol_days
            })

        if count % 10 == 0:
            print(f"Processed {count} tickers, found {len(results)} with volatile days")

    except Exception as e:
        continue

# Sort results by high_vol_days descending
results.sort(key=lambda x: x['high_vol_days'], reverse=True)

print(f"\\nTotal companies with high volatility days: {len(results)}")
print("\\nTop 10 companies:")
for i, company in enumerate(results[:10]):
    print(f"{i+1}. {company['company_name']} ({company['ticker']}): {company['high_vol_days']} days")

top_5 = results[:5]

print("__RESULT__:")
print(json.dumps(top_5))

